cat > Components/Pages/Admin/Users.razor << 'RAZOR'
@page "/admin/users"
@using Microsoft.AspNetCore.Identity
@attribute [Authorize(Roles = "Admin")]
@rendermode InteractiveServer
@inject UserManager<IdentityUser> UserManager

<PageTitle>User Management</PageTitle>

<h1>User Management</h1>
<p>All registered users and their assigned roles.</p>

@if (users is null)
{
    <p><em>Loading…</em></p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Email</th>
                <th>Roles</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var u in users)
            {
                <tr>
                    <td>@u.Email</td>
                    <td>@string.Join(", ", u.Roles)</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<UserWithRoles>? users;

    protected override async Task OnInitializedAsync()
    {
        var allUsers = UserManager.Users.ToList();
        users = new List<UserWithRoles>();
        foreach (var user in allUsers)
        {
            var roles = await UserManager.GetRolesAsync(user);
            users.Add(new UserWithRoles(user.Email!, roles));
        }
    }

    private record UserWithRoles(string Email, IList<string> Roles);
}
RAZOR

